const webhookBody = $('Discord Webhook').item.json.body;
const message   = (webhookBody.message   || '').trim();
const channelId = webhookBody.channelId  || '';
const userId    = webhookBody.userId     || '';
const username  = webhookBody.username   || 'user';
const messageId = webhookBody.messageId  || '';

if (!message) throw new Error('Empty message received from Discord');

const stdout = $input.first().json.stdout || '';
const availableSkills = stdout
  .split('\n')
  .map(p => p.trim())
  .filter(Boolean)
  .map(p => p.replace('/workspace/', '~/.agent-co/workspace/'));

const ws = '~/.agent-co/workspace';
const coreSkills = [
  `${ws}/context/core/identity.md`,
  `${ws}/context/core/co-founder.md`,
  `${ws}/context/core/problem-solver.md`,
  `${ws}/context/core/learning-capture.md`,
  `${ws}/context/core/memory-recall.md`,
  `${ws}/context/core/technical-awareness.md`,
  `${ws}/context/core/lead-management.md`,
  `${ws}/context/core/context-anchor.md`,
  `${ws}/context/self-build/self-architecture.md`,
  `${ws}/memory/decisions.md`,
];

const technicalGuides = [
  `${ws}/context/technical-guides/backend-guide.md`,
  `${ws}/context/technical-guides/code-patterns-guide.md`,
  `${ws}/context/technical-guides/frontend-guide.md`,
  `${ws}/context/technical-guides/infrastructure-guide.md`,
  `${ws}/context/technical-guides/seo-playbook.md`,
  `${ws}/context/technical-guides/stateful-systems-guide.md`,
  `${ws}/context/design/ui-design-guide.md`,
];

const skillList = availableSkills.length
  ? availableSkills.map(p => `- ${p}`).join('\n')
  : '(none available)';

const selectorPrompt = `You are selecting which skill/context files to load before working on a task.

Core files are always loaded — do not include them in your selection:
${coreSkills.map(p => `- ${p}`).join('\n')}

Available domain skills:
${skillList}

SKILL BUNDLES — load these as complete groups when the condition is met:

**Technical bundle** (load ALL of these when the task involves code analysis, debugging, coding, technical research, architecture, infrastructure, refactoring, reviewing code, building features, fixing bugs, or any software engineering work):
${technicalGuides.map(p => `- ${p}`).join('\n')}

**Delegation bundle** (load these when the task is non-trivial and would benefit from the agent delegating to specialized employee agents — research, coding, debugging, writing, analysis, multi-step work):
- ${ws}/context/self-build/delegation.md
- ${ws}/context/self-build/agents/employees/REGISTRY.md
- ${ws}/context/agent-co-architecture.md

Task: "${message}"

Select every skill file that would meaningfully improve your work on this task.
Think beyond what is explicitly stated — for example:
- Building any website or client-facing page implies SEO matters even if not mentioned
- Lead research implies knowing the outreach approach and email patterns
- Any frontend build implies design context is relevant (ui-design-guide.md is part of the technical bundle)
- Any code analysis, coding, debugging, technical research, or engineering task should load the ENTIRE technical bundle above — do not cherry-pick individual guides from it

Return ONLY a valid JSON array of the full file paths you want loaded.
No explanation, no markdown, no code fences.
If no domain skills are relevant, return: []`;

return [{ json: {
  selectorPrompt,
  availableSkills,
  coreSkills,
  technicalGuides,
  message,
  channelId,
  userId,
  username,
  messageId,
}}];

const relayResult   = $input.first().json;
const selectorData  = $('Build Selector Prompt').item.json;

let selectedSkills = [];
if (relayResult.success && relayResult.output) {
  try {
    const clean = relayResult.output
      .replace(/```json\s*/gi, '')
      .replace(/```\s*/gi, '')
      .trim();
    const parsed = JSON.parse(clean);
    if (Array.isArray(parsed)) selectedSkills = parsed;
  } catch (e) {
    // Parsing failed — proceed with core skills only
  }
}

const available = new Set(selectorData.availableSkills);
let validSkills = selectedSkills.filter(p => available.has(p));

const techGuides = selectorData.technicalGuides || [];
const hasTechGuide = validSkills.some(p => p.includes('/technical-guides/') || p.includes('/design/'));
if (hasTechGuide && techGuides.length > 0) {
  const nonTech = validSkills.filter(p => !p.includes('/technical-guides/') && !p.includes('/design/'));
  validSkills = [...nonTech, ...techGuides.filter(p => available.has(p))];
}

const ws = '~/.agent-co/workspace';
const hasDelegation = validSkills.some(p => p.includes('delegation.md'));
if (hasDelegation) {
  const delegationExtras = [
    `${ws}/context/self-build/agents/employees/REGISTRY.md`,
    `${ws}/context/agent-co-architecture.md`,
  ];
  for (const p of delegationExtras) {
    if (available.has(p) && !validSkills.includes(p)) validSkills.push(p);
  }
}

validSkills = [...new Set(validSkills)];

const readList = validSkills.map(p => `  - ${p}`).join('\n');

const enrichedTask = validSkills.length > 0 ? [
  'Load these domain skill files for this task:',
  readList,
  '',
  '---',
  `Request from ${selectorData.username}:`,
  selectorData.message,
].join('\n') : `Request from ${selectorData.username}:\n${selectorData.message}`;

return [{ json: {
  enrichedTask,
  selectedSkills:  validSkills,
  channelId:       selectorData.channelId,
  userId:          selectorData.userId,
  username:        selectorData.username,
  messageId:       selectorData.messageId,
  originalMessage: selectorData.message,
}}];

