const webhook = $('Discord Webhook').item.json;
const body = webhook.body || {};
const channelId = body.channelId || '';
const username = body.username || '';
const message = body.message || '';

// Collect node results from the execution
const nodeNames = ['Check Relay Health', 'Relay Up?', 'Check Session', 'Can Resume?'];
const nodes = [];

for (const name of nodeNames) {
  try {
    const item = $(name).item;
    nodes.push({ name, type: 'check', status: 'success', outputPreview: JSON.stringify(item.json).slice(0, 200) });
  } catch {
    // Node didn't execute in this path — skip
  }
}

// Check which path was taken
let path = 'unknown';
try {
  $('Build Resume Prompt').item;
  path = 'resume';
  nodes.push({ name: 'Build Resume Prompt', type: 'code', status: 'success' });
} catch {
  try {
    $('Build Full Prompt').item;
    path = 'selector';
    nodes.push({ name: 'List Available Skills', type: 'command', status: 'success' });
    nodes.push({ name: 'Build Selector Prompt', type: 'code', status: 'success' });
    nodes.push({ name: 'Call Skill Selector', type: 'http', status: 'success' });
    nodes.push({ name: 'Build Full Prompt', type: 'code', status: 'success' });
  } catch { /* neither path */ }
}

// Claude relay result
const relayResult = $('Call Claude Via Relay').item.json;
nodes.push({
  name: 'Call Claude Via Relay',
  type: 'http',
  status: relayResult.success ? 'success' : 'error',
  durationMs: relayResult.durationMs,
  outputPreview: (relayResult.output || '').slice(0, 200),
  error: relayResult.success ? undefined : relayResult.error,
});

// Discord reply
try {
  const discordResult = $('Post Discord Reply').item.json;
  nodes.push({
    name: 'Post Discord Reply',
    type: 'http',
    status: discordResult.success ? 'success' : 'error',
    error: discordResult.success ? undefined : discordResult.error,
  });
} catch (e) {
  nodes.push({ name: 'Post Discord Reply', type: 'http', status: 'error', error: String(e).slice(0, 200) });
}

return [{ json: {
  workflowName: '10-discord-gateway',
  executionId: $execution.id,
  status: 'success',
  traceId: relayResult.traceId || null,
  path,
  channelId,
  username,
  durationMs: relayResult.durationMs,
  nodes,
  message: message.slice(0, 100),
  resumed: relayResult.sessionResumed || false,
}}];

